tool.command:
## RepeatMasker 4.2.4 uses the partitioned FamDB (v3) library format and no
## longer bundles a repeat library or accepts -libdir. For Dfam-based masking
## we export the families for the requested clade from a cached FamDB library
## (installed by the RepeatMasker Dfam data manager) with famdb.py, and pass
## the result to RepeatMasker as a custom -lib.
#if $repeat_source.source_type == "cached":
  famdb.py -i '${repeat_source.famdb.fields.path}'
      families -a -d -f fasta_name --include-class-in-name
      '${repeat_source.species_name}'
  > repeats.fa &&
#end if

ln -s '${input_fasta}' rm_input.fasta &&

## The RepeatMasker Conda package is configured with a FamDB directory but
## ships no library data, and RepeatMasker probes it at startup even in -lib
## mode. Clearing FAMDB_DIR skips that probe so masking runs from the -lib
## library alone (the cached export above already used famdb.py directly).
FAMDB_DIR='' RepeatMasker -dir \$(pwd)
#if $repeat_source.source_type == "cached":
  -lib repeats.fa
#else if $repeat_source.source_type == "library":
  -lib '${repeat_source.repeat_lib}'
  -cutoff '${repeat_source.cutoff}'
#end if
-parallel \${GALAXY_SLOTS:-1}
${gff}
${excln}
${advanced.is_only}
${advanced.is_clip}
${advanced.no_is}
${advanced.rodspec}
${advanced.primspec}
${advanced.nolow}
${advanced.noint}
${advanced.norna}
${advanced.alu}
${advanced.div}
${advanced.search_speed}
-frag ${advanced.frag}
## -maxsize ${advanced.maxsize}
#if str($advanced.gc):
  -gc ${advanced.gc}
#end if
${advanced.gccalc}
${advanced.nocut}
${advanced.keep_alignments}
${advanced.invert_alignments}
${advanced.xout}
${xsmall}
${advanced.poly}
rm_input.fasta &&
#if $advanced.is_only != '-is_only':
  mv rm_input.fasta.masked '${output_masked_genome}' &&
  sed -E 's/^ *// ; s/ *$//; s/\+ //; s/ +/\t/g ;  1,2c SW score\t% div.\t% del.\t% ins.\tquery sequence\tpos in  query: begin\tend\t(left)\trepeat\tclass/family\tpos in repeat: begin\tend\t(left)\tID' rm_input.fasta.out >'${output_log}' &&
  mv rm_input.fasta.tbl '${output_table}' &&
  #if $gff == '-gff':
    mv rm_input.fasta.out.gff '${output_gff}' &&
  #end if
  #if $advanced.keep_alignments == '-ali':
    mv rm_input.fasta.align '${output_alignment}' &&
  #end if
  #if $advanced.poly == '-poly':
    sed -E 's/^ *// ; s/ *$//; s/\+ //; s/ +/\t/g' rm_input.fasta.polyout >'${output_polymorphic}' &&
  #end if
#end if
if [ -f 'rm_input.fasta.cat.gz' ]; then
  zcat 'rm_input.fasta.cat.gz' > '${output_repeat_catalog}';
else
  mv rm_input.fasta.cat '${output_repeat_catalog}';
fi
